import{_ as a,c as t,o as l,ag as o}from"./chunks/framework.DPDPlp3K.js";const m=JSON.parse('{"title":"全局设置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduce/Config/GlobalConfig.md","filePath":"guide/introduce/Config/GlobalConfig.md","lastUpdated":1743515914000}'),i={name:"guide/introduce/Config/GlobalConfig.md"};function r(s,e,d,n,h,c){return l(),t("div",null,e[0]||(e[0]=[o('<h1 id="全局设置" tabindex="-1">全局设置 <a class="header-anchor" href="#全局设置" aria-label="Permalink to &quot;全局设置&quot;">​</a></h1><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>全局配置修改后<strong>必须重启</strong> biliup 才能生效。无特殊需求不建议修改默认值。</p></div><hr><h2 id="下载器" tabindex="-1">下载器 <a class="header-anchor" href="#下载器" aria-label="Permalink to &quot;下载器&quot;">​</a></h2><h3 id="stream-gears-默认" tabindex="-1">stream-gears（默认） <a class="header-anchor" href="#stream-gears-默认" aria-label="Permalink to &quot;stream-gears（默认）&quot;">​</a></h3><ul><li>默认下载器，无需安装 FFmpeg。</li><li>自动处理主播 PK 等导致的分辨率变化，防止视频花屏。</li><li>不支持 HLS 流（如 B站 APEX 分区），此类流需改用 <code>streamlink</code>。</li></ul><h3 id="streamlink" tabindex="-1">streamlink <a class="header-anchor" href="#streamlink" aria-label="Permalink to &quot;streamlink&quot;">​</a></h3><ul><li>HLS 多线程下载。</li><li>自动识别是否需要 HLS 模式，不支持的流将回退到 FFmpeg。</li><li>需要安装 FFmpeg。</li></ul><h3 id="ffmpeg" tabindex="-1">ffmpeg <a class="header-anchor" href="#ffmpeg" aria-label="Permalink to &quot;ffmpeg&quot;">​</a></h3><ul><li>最通用的音视频下载工具，兼容性强。</li><li>需要安装 FFmpeg。</li></ul><h3 id="sync-downloader-边录边传" tabindex="-1">sync-downloader（边录边传） <a class="header-anchor" href="#sync-downloader-边录边传" aria-label="Permalink to &quot;sync-downloader（边录边传）&quot;">​</a></h3><ul><li>流式视频上传技术，录制过程中实时上传。</li><li>直播结束后自动投稿送审。</li><li>极低资源占用：1核 0.5G 内存即可同时录制 10 个直播间，数据零落盘。</li></ul><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>强依赖稳定上传带宽，确保上传速率 ≥ 下载速率，否则可能内存溢出（OOM）。 并非所有平台都支持此功能，具体请自行测试。</p></div><hr><h2 id="视频分段设置" tabindex="-1">视频分段设置 <a class="header-anchor" href="#视频分段设置" aria-label="Permalink to &quot;视频分段设置&quot;">​</a></h2><h3 id="分段大小-file-size" tabindex="-1">分段大小（file_size） <a class="header-anchor" href="#分段大小-file-size" aria-label="Permalink to &quot;分段大小（file_size）&quot;">​</a></h3><p>按文件大小分段，单位 Byte。例：<code>4294967296</code> ≈ 4GB。</p><h3 id="分段时长-segment-time" tabindex="-1">分段时长（segment_time） <a class="header-anchor" href="#分段时长-segment-time" aria-label="Permalink to &quot;分段时长（segment_time）&quot;">​</a></h3><p>按录制时长分段，格式 <code>00:00:00</code>（时:分:秒）。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>分段大小和分段时长可同时设置，先触发哪个就按哪个分段。</p></div><hr><h2 id="文件名模板-filename-prefix" tabindex="-1">文件名模板（filename_prefix） <a class="header-anchor" href="#文件名模板-filename-prefix" aria-label="Permalink to &quot;文件名模板（filename_prefix）&quot;">​</a></h2><p>默认：<code>{streamer}%Y-%m-%dT%H_%M_%S</code></p><p>示例输出：<code>主播名2025-03-25T12_46_42</code></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>如果修改模板，必须包含 <code>{streamer}</code> 变量（放在第一位）和 <code>%Y-%m-%d %H_%M_%S</code> 时间戳。 额外支持 <code>{title}</code> 变量（直播标题），注意控制字符数不超过 B站限制。</p></div><hr><h2 id="分段后处理-segment-processor" tabindex="-1">分段后处理（segment_processor） <a class="header-anchor" href="#分段后处理-segment-processor" aria-label="Permalink to &quot;分段后处理（segment_processor）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>处理器</th><th>说明</th></tr></thead><tbody><tr><td><code>remux:mp4</code></td><td>将录制文件重新封装为 MP4 格式</td></tr><tr><td>自定义脚本</td><td>可指定 Python 脚本进行自定义处理（如弹幕压制）</td></tr></tbody></table><blockquote><p>此功能需要额外配置，一般用户无需使用。</p></blockquote><hr><h2 id="下载线程池大小-pool1-size" tabindex="-1">下载线程池大小（pool1_size） <a class="header-anchor" href="#下载线程池大小-pool1-size" aria-label="Permalink to &quot;下载线程池大小（pool1_size）&quot;">​</a></h2><p>同时录制的最大直播间数，默认 <code>5</code>。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>如果添加了 6 个主播但只设置 5 个线程，会有一个主播不进行录制。</p></div><hr><h2 id="碎片过滤-filtering-threshold" tabindex="-1">碎片过滤（filtering_threshold） <a class="header-anchor" href="#碎片过滤-filtering-threshold" aria-label="Permalink to &quot;碎片过滤（filtering_threshold）&quot;">​</a></h2><p>过滤因网络波动/主播断流导致的视频碎片，默认 20（单位 MB）。</p><hr><h2 id="下播延迟检测-delay" tabindex="-1">下播延迟检测（delay） <a class="header-anchor" href="#下播延迟检测-delay" aria-label="Permalink to &quot;下播延迟检测（delay）&quot;">​</a></h2><p>检测到主播下播后延迟指定时间再次确认，避免提前结束导致分稿件。默认 <code>0</code> 秒。</p><p>适用于一天多次开播的主播，根据其下播和再次开播的间隔设置。</p><hr><h2 id="直播事件检测间隔-event-loop-interval" tabindex="-1">直播事件检测间隔（event_loop_interval） <a class="header-anchor" href="#直播事件检测间隔-event-loop-interval" aria-label="Permalink to &quot;直播事件检测间隔（event_loop_interval）&quot;">​</a></h2><p>单个主播的检测间隔，单位秒。例如虎牙有 10 个主播，每个间隔 10 秒检测一次。</p><hr><h2 id="上传设置" tabindex="-1">上传设置 <a class="header-anchor" href="#上传设置" aria-label="Permalink to &quot;上传设置&quot;">​</a></h2><p>保持默认即可，非必要不要修改。如需手动调整：</p><ul><li><strong>上传线路</strong>：bda2 / ws / qn，自动选择最优。</li><li><strong>并发线程</strong>：上传失败时从 1 开始逐渐增加。</li></ul>',47)]))}const u=a(i,[["render",r]]);export{m as __pageData,u as default};
